const payload = msg.payload || {};
const orig = msg.originalPayload || payload;

// Get services - from payload or from the product field
let requested_services = payload.requested_services || orig.product || '';
const zip_code = payload.zip_code || orig.zip_code || '';

// Normalize product to service keys for bidagent
if (!requested_services) {
    msg.payload = { success: false, error: 'requested_services is required' };
    return msg;
}

(async () => {
    try {
        // Fetch service mapping through Node-RED pricebook proxy (not CRM directly)
        const pbResp = await axios.get('http://bodhi.lab:1880/api/curbclass/bidagent/pricebook');
        const pbData = pbResp.data;
        const servicesList = pbData && pbData.data && pbData.data.services || [];

        const serviceMap = {};
        servicesList.forEach(function(svc) {
            if (svc.name && svc.bidagentServiceKey) {
                serviceMap[svc.name] = svc.bidagentServiceKey;
            }
        });

        const services = requested_services.split(/[,|]/).map(function(s) {
            var trimmed = s.trim();
            return serviceMap[trimmed] || trimmed;
        }).filter(Boolean).join(',');

        msg.originalPayload = orig;

        // Forward image URLs if present in msg.originalPayload/payload
        let image_urls = '';
        if (orig.imageUrls) {
            if (Array.isArray(orig.imageUrls)) {
                image_urls = orig.imageUrls.join(',');
            } else {
                image_urls = String(orig.imageUrls);
            }
        }

        msg.method = "POST";
        msg.url = "http://bodhi.lab:8000/api/v1/estimate";
        msg.headers = { "Content-Type": "application/x-www-form-urlencoded" };
        msg.payload = "requested_services=" + encodeURIComponent(services) +
                      "&zip_code=" + encodeURIComponent(zip_code) +
                      "&customer_name=" + encodeURIComponent(orig.name || '') +
                      "&customer_email=" + encodeURIComponent(orig.email || '') +
                      "&customer_phone=" + encodeURIComponent(orig.phone || '') +
                      "&image_urls=" + encodeURIComponent(image_urls);
        node.send(msg);
        node.done();
    } catch (error) {
        node.error("Failed to fetch service mapping: " + error.message, msg);
        msg.payload = { success: false, error: 'Service mapping unavailable: ' + error.message };
        node.send(msg);
        node.done();
    }
})();

const result = msg.payload;
const orig = msg.originalPayload || {};

if (!result || !result.status) {
    msg.payload = { success: false, error: 'BidAgent unavailable' };
    return [null, msg];
}

result.originalPayload = orig;

if (result.status === 'rejected') {
    msg.title = "⛔ CurbClass Estimate Rejected";
    msg.priority = 7;
    msg.payload = 'Customer: ' + (orig.name || 'Unknown') + '\n' +
                  'Email: ' + (orig.email || 'N/A') + '\n' +
                  'Reason: ' + (result.rejection || 'No reason given') + '\n\n' +
                  'This estimate was auto-rejected by BidAgent. Follow up manually.';
    return [null, msg];
}

// Parse product string
const rawProduct = orig.product || orig.requested_services || '';
let servicesList = rawProduct;
let style = '';
let schedule = '';

if (rawProduct.includes('|')) {
    const parts = rawProduct.split(/\s*\|\s*/);
    parts.forEach(function(part) {
        if (part.toLowerCase().startsWith('style:')) {
            style = part.substring(6).trim();
        } else if (part.toLowerCase().startsWith('services:')) {
            servicesList = part.substring(9).trim();
        } else if (part.toLowerCase().startsWith('schedule:')) {
            schedule = part.substring(9).trim();
        }
    });
}
if (servicesList.toLowerCase().startsWith('services:')) {
    servicesList = servicesList.substring(9).trim();
}

// Build estimate summary with markdown formatting
let quoteLines = [];
(result.itemized_quote || []).forEach(function(item) {
    if (item.error) {
        quoteLines.push('• ⚠️ **' + item.service + '**: ' + item.error);
    } else {
        var priceStr = '';
        if (item.price !== undefined) {
            priceStr = '$' + item.price;
        } else if (item.price_low !== undefined && item.price_high !== undefined) {
            priceStr = (item.price_low === item.price_high) ? '$' + item.price_low : '$' + item.price_low + ' - $' + item.price_high;
        } else {
            priceStr = 'TBD';
        }
        quoteLines.push('• **' + (item.label || item.service) + '**: ' + priceStr);
    }
});

var warningsStr = '';
if (result.warnings && result.warnings.length > 0) {
    warningsStr = '\n\n### ⚠️ Warnings\n' + result.warnings.map(function(w) { return '• ' + w; }).join('\n\n');
}

msg.estimateSummary = quoteLines.join('\n\n');
msg.estimatePrice = result.total !== undefined ? result.total : result.total_low;
msg.estimateLow = result.total_low !== undefined ? result.total_low : result.total;
msg.estimateHigh = result.total_high !== undefined ? result.total_high : result.total;
msg.bidagentWarnings = result.warnings || [];
msg.bidagentStatus = result.status;
msg.estimateData = result;

var totalStr = '';
if (result.total !== undefined) {
    totalStr = '$' + result.total;
} else if (result.total_low !== undefined && result.total_high !== undefined) {
    totalStr = (result.total_low === result.total_high) ? '$' + result.total_low : '$' + result.total_low + ' - $' + result.total_high;
} else {
    totalStr = 'TBD';
}

// Exclude Job Executive Summary (result.description) from gotify (contractor facing)
let descStr = '';
if (result.contractor_notes) {
    descStr += '### 🔧 Crew Brief & Rationale\n' + result.contractor_notes + '\n\n';
}

msg.title = "💰 CurbClass Estimate Generated: " + (orig.name || 'Unknown');
msg.priority = 5;

let payloadLines = [];
payloadLines.push('**Customer:** ' + (orig.name || 'Unknown'));
payloadLines.push('**Email:** ' + (orig.email || 'N/A'));
if (orig.phone) payloadLines.push('**Phone:** ' + orig.phone);
if (quoteLines.length === 0 && servicesList) {
    payloadLines.push('**Services:** ' + servicesList);
}
if (style) payloadLines.push('**Style:** ' + style);
if (schedule) payloadLines.push('**Schedule:** ' + schedule);
if (orig.zip_code) payloadLines.push('**ZIP:** ' + orig.zip_code);

msg.payload = payloadLines.join('\n\n') + '\n\n' +
              descStr +
              '### 💰 AI Estimate\n' +
              quoteLines.join('\n\n') + '\n\n' +
              '**Estimated Total:** ' + totalStr +
              warningsStr;

msg.extras = {
    "client::display": {
        "contentType": "text/markdown"
    }
};

return [msg, null];

const token = env.get("CURBCLASS_TWENTY_TOKEN");
const baseUrl = env.get("TWENTY_BASE_URL");

msg.method = "GET";
msg.url = baseUrl + "/rest/services";
msg.headers = {
    "Authorization": "Bearer " + token
};
return msg;

const isEnrichment = msg.payload.isEnrichment;
const skipped = msg.payload.skipped;

if (skipped) {
    msg.title = `ChassisShield Lead (Step 2 Skipped): ${msg.payload.email}`;
    msg.payload = `Email: ${msg.payload.email}\n\nUser skipped profile enrichment (Step 2). Opportunity marked 'Skipped Profile' (Enrichment Pending) with a follow-up task to reach out manually.`;
} else if (isEnrichment) {
    msg.title = `ChassisShield Lead Enriched: ${msg.payload.name || msg.payload.email}`;
    msg.payload = `Name: ${msg.payload.name || 'Not specified'}\nEmail: ${msg.payload.email}\nVehicle: ${msg.payload.carType || 'Not specified'}\nLocation: ${msg.payload.location || 'Not specified'}\nComments: ${msg.payload.comments || 'None'}`;
} else {
    msg.title = `New ChassisShield Lead: ${msg.payload.email}`;
    msg.payload = `New waitlist signup:\nEmail: ${msg.payload.email}\nLocation: ${msg.payload.location || 'Not specified'}\n\nAwaiting Step 2 details.`;
}
msg.priority = 6;
msg.extras = { "client::display": { "contentType": "text/markdown" } };
return msg;

msg.originalPayload = msg.payload; // Save for Opportunity/Note creation later
const name = (msg.payload.name || '').trim();
const email = (msg.payload.email || '').trim().toLowerCase();

const nameParts = name.split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ');

msg.lead = {
    firstName: firstName,
    lastName: lastName,
    email: email
};
msg.jobTitle = "Chassis Shield Lead";
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
const personId = person ? person.id : '';
msg.payload = {
    success: true,
    twentyUrl: personId ? `https://chassisshield.crm.cosmoslab.dev/object/person/${personId}` : ''
};
msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json'
};
return msg;

delete msg.res;
delete msg.req;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
const personId = person ? person.id : '';
msg.personId = personId;

if (!personId) {
    node.warn("ChassisShield: Person create/update failed - " + JSON.stringify(msg.payload));

    const lead = msg.originalPayload || {};
    msg.title = "\u26a0\ufe0f ChassisShield CRM Sync FAILED";
    msg.priority = 9;
    msg.payload = `Lead (${lead.email || 'no email'}, ${lead.name || 'Unknown'}) did NOT sync to CRM.\n\nTwenty API response:\n${JSON.stringify(msg.payload)}`;
    return [null, msg]; // Stop the CRM chain, send a Gotify alert instead
}

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities?filter=pointOfContact.id[eq]:${encodeURIComponent(personId)}`;

return [msg, null];

const searchData = msg.payload;
const existing = searchData && searchData.data && searchData.data.opportunities && searchData.data.opportunities[0];
msg.existingOpportunityId = existing ? existing.id : '';

const data = msg.originalPayload;
const isEnrichment = !!data.isEnrichment;
const skipped = !!data.skipped;
const displayName = data.name || data.email;


if (!isEnrichment) {
    // Step 1: create the Opportunity right away, marked incomplete.
    // If one already exists (e.g. a retried Step 1 call), there's nothing to do.
    if (msg.existingOpportunityId) {
        return null;
    }
    msg.opportunityCase = 'incomplete';
    msg.method = "POST";
    msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
    msg.payload = {
        name: `ChassisShield Waitlist (Profile Incomplete): ${displayName}`,
        stage: "SCREENING",
        pointOfContactId: msg.personId
    };
} else if (skipped) {
    msg.opportunityCase = 'skipped';
    msg.payload = {
        name: `ChassisShield Waitlist (Skipped Profile): ${displayName}`,
        stage: "SCREENING"
    };
    if (msg.existingOpportunityId) {
        msg.method = "PATCH";
        msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${msg.existingOpportunityId}`;
    } else {
        msg.method = "POST";
        msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
        msg.payload.pointOfContactId = msg.personId;
    }
} else {
    msg.opportunityCase = 'enriched';
    msg.payload = {
        name: `ChassisShield Waitlist: ${displayName}`,
        stage: "MEETING"
    };
    if (msg.existingOpportunityId) {
        msg.method = "PATCH";
        msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${msg.existingOpportunityId}`;
    } else {
        msg.method = "POST";
        msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
        msg.payload.pointOfContactId = msg.personId;
    }
}

return msg;

const data = msg.originalPayload;

let markdown = `**Vehicle:** ${data.carType || 'Not specified'}\n`;
markdown += `**Location:** ${data.location || 'Not specified'}\n\n`;
if (data.comments) {
    markdown += `**Comments:**\n${data.comments}\n`;
}

msg.noteTitle = "Chassis Shield Waitlist Enrichment";
msg.noteMarkdown = markdown;
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

if (msg.noteResult && !msg.noteResult.success) {
    node.warn("ChassisShield: Note creation/link failed - " + JSON.stringify(msg.noteResult.error || msg.noteResult.details));
}
return null;

const data = msg.originalPayload;

msg.taskTitle = `Follow up: ${data.name || 'Waitlist Lead'} (Chassis Shield enrichment)`;
msg.taskMarkdown = `**Vehicle:** ${data.carType || 'Not specified'}\n**Location:** ${data.location || 'Not specified'}\n\nReview enrichment details and reach out within 24 hours.`;
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

if (msg.taskResult && !msg.taskResult.success) {
    node.warn("ChassisShield: Task creation/link failed - " + JSON.stringify(msg.taskResult.error || msg.taskResult.details));
}
return null;

const result = msg.payload && msg.payload.data && (msg.payload.data.createOpportunity || msg.payload.data.updateOpportunity);
const opportunityId = result ? result.id : '';
msg.opportunityId = opportunityId;

if (!opportunityId) {
    node.warn("ChassisShield: Opportunity create/update failed - " + JSON.stringify(msg.payload && msg.payload.errors));
    return [null, null, null];
}

if (msg.opportunityCase === 'enriched') {
    return [RED.util.cloneMessage(msg), RED.util.cloneMessage(msg), null];
}

if (msg.opportunityCase === 'skipped') {
    return [null, null, msg];
}

// 'incomplete' - Opportunity created, nothing further to do
return [null, null, null];

const data = msg.originalPayload;

msg.taskTitle = `Follow up: ${data.email} (Chassis Shield - no profile details provided)`;
msg.taskMarkdown = "Reach out manually; user skipped the profile enrichment step.";
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

const p = msg.payload || {};
const email = (p.email || '').trim();

if (!email) {
    const errMsg = Object.assign({}, msg);
    errMsg.statusCode = 400;
    errMsg.payload = {
        success: false,
        error: 'Missing required field: email'
    };
    errMsg.headers = { 'Content-Type': 'application/json' };
    return [null, null, errMsg];
}

return [RED.util.cloneMessage(msg), RED.util.cloneMessage(msg), null];

const err = msg.error || {};
const src = err.source ? ` [source: ${err.source.name || err.source.id}]` : '';
const errText = (err.message || String(err)) + src;

// Check which brand this error belongs to (CurbClass vs ChassisShield)
const isCurbClass = msg.twentyHost && msg.twentyHost.includes('curbclass');

if (!msg.res || msg.res.headersSent) {
    node.warn(`Background error [${isCurbClass ? 'CurbClass' : 'ChassisShield'}]: ${errText}`);

    // Background fallback for CurbClass ONLY (ChassisShield has no customer emails via Resend here)
    if (isCurbClass) {
        const orig = msg.originalPayload || msg.payload || {};
        const name = orig.name || 'Unknown';
        const email = orig.email || 'N/A';

        if (email && email !== 'N/A') {
            const fallbackMsg = RED.util.cloneMessage(msg);
            fallbackMsg.payload = {
                customerEmail: email,
                customerName: name,
                customerPhone: orig.phone || '',
                zipCode: orig.zip_code || '',
                product: orig.product || 'General inquiry',
                message: orig.message || '',
                estimate: null
            };
            return [null, fallbackMsg];
        }
    }
    return null;
}

node.warn(`Synchronous error (will 500) [${isCurbClass ? 'CurbClass' : 'ChassisShield'}]: ${errText}`);

msg.statusCode = 500;
msg.payload = { success: false, error: err.message || "Failed to process lead." };
msg.headers = { "Content-Type": "application/json" };
return [msg, null];

const p = msg.payload || {};
const name = (p.name || '').trim();
const email = (p.email || '').trim();
const phone = (p.phone || '').trim();

const missing = [];
if (!name) missing.push('name');
if (!email) missing.push('email');
if (!phone) missing.push('phone');

if (missing.length > 0) {
    const errMsg = Object.assign({}, msg);
    errMsg.statusCode = 400;
    errMsg.payload = {
        success: false,
        error: `Missing required field(s): ${missing.join(', ')}`
    };
    errMsg.headers = { 'Content-Type': 'application/json' };
    return [null, errMsg];
}


return [msg, null];

msg.originalPayload = msg.payload; // Save for later
const name = (msg.payload.name || '').trim();
const email = (msg.payload.email || '').trim().toLowerCase();
let phone = (msg.payload.phone || '').trim();

let validPhone = null;
const cleanPhone = phone.replace(/\D/g, '');
if (cleanPhone.length === 10) {
    validPhone = '+1' + cleanPhone;
} else if (cleanPhone.length > 10) {
    validPhone = phone.startsWith('+') ? phone : '+' + cleanPhone;
}

const nameParts = name.split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ');

msg.lead = {
    firstName: firstName,
    lastName: lastName,
    email: email,
    phone: validPhone
};
msg.jobTitle = "Curb Class Lead";
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

let personId = '';
const payload = msg.payload || {};

if (payload.id) {
    personId = payload.id;
} else if (payload.data) {
    if (payload.data.id) {
        personId = payload.data.id;
    } else if (payload.data.createPerson && payload.data.createPerson.id) {
        personId = payload.data.createPerson.id;
    } else if (payload.data.updatePerson && payload.data.updatePerson.id) {
        personId = payload.data.updatePerson.id;
    } else if (payload.data.searchPerson && payload.data.searchPerson.id) {
        personId = payload.data.searchPerson.id;
    } else if (payload.data.people && payload.data.people[0] && payload.data.people[0].id) {
        personId = payload.data.people[0].id;
    }
}

msg.personId = personId;

if (!personId) {
    node.warn("CurbClass: Person upsert failed - " + JSON.stringify(msg.payload));
}

// Only build opportunity if person was found/created successfully
if (personId) {
    return [msg, msg, null];
} else {
    return [null, null, msg];
}

let intakeDetails = `Product: ${msg.originalPayload.product || 'General inquiry'}\n`;
if (msg.originalPayload.message) {
    intakeDetails += `\nMessage:\n${msg.originalPayload.message}\n`;
}
if (msg.originalPayload.imageUrls && msg.originalPayload.imageUrls.length > 0) {
    intakeDetails += `\nProperty Photos:\n`;
    msg.originalPayload.imageUrls.forEach((url, i) => {
        intakeDetails += `- Photo ${i + 1}: ${url}\n`;
    });
}

msg.method = "POST";
msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
msg.payload = {
    name: "CurbClass: " + (msg.originalPayload.name || "New Lead"),
    stage: "NEW",
    pointOfContactId: msg.personId,
    intakeDetails: intakeDetails
};

return msg;

let oppId = '';
const payload = msg.payload || {};

if (payload.id) {
    oppId = payload.id;
} else if (payload.data) {
    if (payload.data.id) {
        oppId = payload.data.id;
    } else if (payload.data.createOpportunity && payload.data.createOpportunity.id) {
        oppId = payload.data.createOpportunity.id;
    } else if (payload.data.updateOpportunity && payload.data.updateOpportunity.id) {
        oppId = payload.data.updateOpportunity.id;
    } else if (payload.data.opportunities && payload.data.opportunities[0] && payload.data.opportunities[0].id) {
        oppId = payload.data.opportunities[0].id;
    }
}

msg.opportunityId = oppId;

if (!oppId) {
    node.warn("CurbClass: Opportunity creation failed - " + JSON.stringify(msg.payload));
}

const product = msg.originalPayload.product || '';
const imageUrls = msg.originalPayload.imageUrls || [];
const isServiceInquiry = product.includes('Service Bundle Inquiry') || product.includes('Refresh Estimate');
const hasPhotos = imageUrls && imageUrls.length > 0;

if (isServiceInquiry && hasPhotos) {
    return [msg, null, msg];
} else {
    return [null, msg, msg];
}

const oppId = msg.opportunityId;
if (!oppId || !msg.originalPayload.imageUrls || msg.originalPayload.imageUrls.length === 0) {
    return null;
}

const token = env.get("CURBCLASS_TWENTY_TOKEN");
const fieldMetadataId = "951c6783-41fd-4f2c-ba4f-f250fcb0fb9e";

(async () => {
    try {
        for (let i = 0; i < msg.originalPayload.imageUrls.length; i++) {
            const url = msg.originalPayload.imageUrls[i];
            const filename = url.substring(url.lastIndexOf('/') + 1);

            const response = await axios.get(url, { responseType: 'arraybuffer' });
            const buffer = Buffer.from(response.data);

            const form = new FormData();
            form.append('operations', JSON.stringify({
                operationName: "UploadFilesFieldFile",
                variables: { file: null, fieldMetadataId: fieldMetadataId },
                query: "mutation UploadFilesFieldFile($file: Upload!, $fieldMetadataId: String!) { uploadFilesFieldFile(file: $file, fieldMetadataId: $fieldMetadataId) { id } }"
            }));
            form.append('map', JSON.stringify({ "1": ["variables.file"] }));
            form.append('1', buffer, { filename: filename, contentType: 'image/jpeg' });

            const uploadRes = await axios.post(env.get("TWENTY_BASE_URL") + "/metadata", form, {
                headers: {
                    ...form.getHeaders(),
                    'Authorization': `Bearer ${token}`,
                    'Host': 'curbclass.localhost:3000'
                }
            });

            const fileId = uploadRes.data && uploadRes.data.data && uploadRes.data.data.uploadFilesFieldFile && uploadRes.data.data.uploadFilesFieldFile.id;
            if (!fileId) continue;

            await axios.post(env.get("TWENTY_BASE_URL") + "/rest/attachments", {
                name: filename,
                fullPath: url,
                targetOpportunityId: oppId,
                fileCategory: "IMAGE",
                file: [{ fileId: fileId, label: filename }]
            }, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Host': 'curbclass.localhost:3000',
                    'Content-Type': 'application/json'
                }
            });
        }
    } catch (err) {
        node.warn("CurbClass: Attachments error: " + err.message);
    }
})();

return null;

const orig = msg.originalPayload || msg.payload || {};

// Output 1: Email path
const m1 = RED.util.cloneMessage(msg);
m1.payload = {
    customerEmail: orig.email || "",
    customerName: orig.name || "",
    customerPhone: orig.phone || "",
    zipCode: orig.zip_code || "",
    product: orig.product || "General inquiry",
    message: orig.message || "",
    estimate: null
};

// Output 2: CRM/Gotify path (uses orig)
const m2 = RED.util.cloneMessage(msg);
m2.payload = orig;

return [m1, m2];

const axios = this.axios || axios;
const p = msg.originalPayload || msg.payload || {};
const name = p.name || '';
const email = p.email || '';
const product = p.product || '';
const imageUrls = p.imageUrls || [];
const zip_code = p.zip_code || '';
const phone = p.phone || '';

let requested_services = '';
const parts = product.split(' | ');
parts.forEach(part => {
    if (part.startsWith('Services: ')) {
        requested_services = part.replace('Services: ', '').split(', ').filter(s => !s.startsWith('Timeline:')).join(',');
    }
});

if (!requested_services) {
    node.error("CurbClass: No requested services in product string", msg);
    return null;
}

(async () => {
    try {
        const pbResp = await axios.get('http://bodhi.lab:1880/api/curbclass/bidagent/pricebook');
        const servicesList = pbResp.data && pbResp.data.data && pbResp.data.data.services || [];

        const serviceMap = {};
        servicesList.forEach(function(svc) {
            if (svc.name && svc.bidagentServiceKey) {
                serviceMap[svc.name] = svc.bidagentServiceKey;
            }
        });

        const services = requested_services.split(/[,|]/).map(function(s) {
            var trimmed = s.trim();
            return serviceMap[trimmed] || trimmed;
        }).filter(Boolean).join(',');

        let image_urls = '';
        if (imageUrls) {
